import{_ as a,c as n,a1 as s,o as t}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Using Social Engineering Toolkit (SET)","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/8-social-engineering/1-Using-SET.md","filePath":"categories/ethical-hacking-labs/8-social-engineering/1-Using-SET.md"}'),i={name:"categories/ethical-hacking-labs/8-social-engineering/1-Using-SET.md"};function o(l,e,p,c,r,d){return t(),n("div",null,e[0]||(e[0]=[s(`<h1 id="using-social-engineering-toolkit-set" tabindex="-1">Using Social Engineering Toolkit (SET) <a class="header-anchor" href="#using-social-engineering-toolkit-set" aria-label="Permalink to &quot;Using Social Engineering Toolkit (SET)&quot;">​</a></h1><p>The Social Engineering Toolkit (SET) is an open-source Python-driven tool designed for pentesting. The SET is specifically designed to perform advanced attacks against human by exploiting their behavior. The attacks built into the toolkit are designed to be targeted and focused attacks against a person or organization used during a penetration test.</p><p><em>SET Manual by TrustedSec: <a href="https://github.com/trustedsec/social-engineer-toolkit/raw/master/readme/User_Manual.pdf" target="_blank" rel="noreferrer">https://github.com/trustedsec/social-engineer-toolkit/raw/master/readme/User_Manual.pdf</a></em></p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Clone a website</li><li>Obtain username and password</li><li>Generate reports for conducted pentesting</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Kali Linux virtual machine</li><li>Any Windows virtual machine</li></ul><h2 id="launch-set" tabindex="-1">Launch SET <a class="header-anchor" href="#launch-set" aria-label="Permalink to &quot;Launch SET&quot;">​</a></h2><p>Log in to Kali Linux; Remember every Kali version comes with pre installed SET, to launch <em>(on Kali 2019.4)</em> go to <strong>Kali Menu &gt; 13 - Social Engineering Tools &gt; SET (Social Engineering Toolkit).</strong></p><p>Accept the Terms of Services by typing <strong>y</strong>.</p><h2 id="clone-a-website" tabindex="-1">Clone a Website <a class="header-anchor" href="#clone-a-website" aria-label="Permalink to &quot;Clone a Website&quot;">​</a></h2><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4fa403cfe8f17a4771b15cab4dfa28cbcaff1385/set-0.png" alt="set-0"></p><p>On the SET Main menu, select the first option <strong>1) Social-Engineering Attacks</strong> by typing the number:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> Select from the menu:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   1) Social-Engineering Attacks</span></span>
<span class="line"><span>   2) Penetration Testing (Fast-Track)</span></span>
<span class="line"><span>   3) Third Party Modules</span></span>
<span class="line"><span>   4) Update the Social-Engineer Toolkit</span></span>
<span class="line"><span>   5) Update SET configuration</span></span>
<span class="line"><span>   6) Help, Credits, and About</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Exit the Social-Engineer Toolkit</span></span></code></pre></div><p>Next, choose <strong>2) Website Attack Vectors</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> Select from the menu:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   1) Spear-Phishing Attack Vectors</span></span>
<span class="line"><span>   2) Website Attack Vectors</span></span>
<span class="line"><span>   3) Infectious Media Generator</span></span>
<span class="line"><span>   4) Create a Payload and Listener</span></span>
<span class="line"><span>   5) Mass Mailer Attack</span></span>
<span class="line"><span>   6) Arduino-Based Attack Vector</span></span>
<span class="line"><span>   7) Wireless Access Point Attack Vector</span></span>
<span class="line"><span>   8) QRCode Generator Attack Vector</span></span>
<span class="line"><span>   9) Powershell Attack Vectors</span></span>
<span class="line"><span>  10) Third Party Modules</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Return back to the main menu.</span></span></code></pre></div><p>The <strong>Web Attack Vector</strong> is a unique way of utilizing multiple web-based attacks in order to compromise the intended target.</p><p>In the next menu, select <strong>3) Credential Harvester Attack Method</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   1) Java Applet Attack Method</span></span>
<span class="line"><span>   2) Metasploit Browser Exploit Method</span></span>
<span class="line"><span>   3) Credential Harvester Attack Method</span></span>
<span class="line"><span>   4) Tabnabbing Attack Method</span></span>
<span class="line"><span>   5) Web Jacking Attack Method</span></span>
<span class="line"><span>   6) Multi-Attack Web Method</span></span>
<span class="line"><span>   7) HTA Attack Method</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Return to Main Menu</span></span></code></pre></div><p>The Credential Harvester Method will utilize web cloning of a website that has a login input(username and password field) and harvest all the information posted to the website.</p><p>Next, select the <strong>2) Site Cloner</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   1) Web Templates</span></span>
<span class="line"><span>   2) Site Cloner</span></span>
<span class="line"><span>   3) Custom Import</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Return to Webattack Menu</span></span></code></pre></div><p>The site cloner is used to clone a website of your choice.</p><p>Next, type the <strong>IP address of Kali Linux</strong> and the URL to be cloned, on this example we will use <em>facebook.com</em> as shown below:</p><p><img src="https://gist.github.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/91679b70b9db90d2be07da923f17f8ff74341609/set-1.png" alt="set-1"></p><p>After that, leave this terminal tab running.</p><h2 id="send-a-crafted-email" tabindex="-1">Send a Crafted Email <a class="header-anchor" href="#send-a-crafted-email" aria-label="Permalink to &quot;Send a Crafted Email&quot;">​</a></h2><p>Now you must send the <strong>IP address</strong> of your <strong>Kali</strong> machine to a target, and trick him to click.</p><p>For this demo, we will use <strong>Gmail</strong>; Launch the web browser on your Kali and login to a Gmail account to compose an email.</p><p>This example will demonstrate just the technical aspect of this technique.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1097d5dacdd68740924956c6632fb4e0be50ee3a/set-2.png" alt="set-2"></p><p>To create a proper link, click <strong>edit link</strong> and first type the actual address under <strong>Link to</strong>, and then type the fake URL in the <strong>Text to display</strong> field.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/22c46de6cebebea15399154a331120c8a3721090/set-3.png" alt="set-3"></p><p>You can verify the fake URL by clicking one time, it will display the actual URL.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1097d5dacdd68740924956c6632fb4e0be50ee3a/set-4.png" alt="set-4"></p><h2 id="log-in-to-the-cloned-website" tabindex="-1">Log in to the Cloned Website <a class="header-anchor" href="#log-in-to-the-cloned-website" aria-label="Permalink to &quot;Log in to the Cloned Website&quot;">​</a></h2><p>Log in to <strong>Windows</strong> as a victim, launch the web browser and sign in to your email (the account that you sent the phishing email).</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/a896b360ac4d9ff1fabcf2825ac0488151defa86/set-5.png" alt="set-5"></p><p>When the victim clicks the URL, will be presented with a replica of facebook.com. The victim will be prompted to enter his/her username and password into the form fields. After the victim enters the Username and Passwords and clicks log in, it does not allow logging in; instead, it redirects to the legitimate Facebook login page, observe the URL.</p><h2 id="obtain-the-credentials" tabindex="-1">Obtain the Credentials <a class="header-anchor" href="#obtain-the-credentials" aria-label="Permalink to &quot;Obtain the Credentials&quot;">​</a></h2><p>The <strong>SET</strong> on Kali Linux fetches the typed <strong>username</strong> and <strong>password</strong>, which can be used by the attacker to gain unauthorized access to the victim&#39;s account.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4f9889f8bf9605f0e4cd1a415f71a77d73eedaee/set-7.png" alt="set-7"></p>`,42)]))}const u=a(i,[["render",o]]);export{g as __pageData,u as default};
